import React, { useState, useEffect } from "react";
import api from "../../api/axios";
import toast from "react-hot-toast";
import "./Admin.css";

const STATUS_BADGE = { pending: "badge-yellow", approved: "badge-green", rejected: "badge-red", enrolled: "badge-blue", completed: "badge-gray" };
const STATUS_LABEL = { pending: "Chờ duyệt", approved: "Đã duyệt", rejected: "Từ chối", enrolled: "Đang học", completed: "Hoàn thành" };

export default function AdminEnrollments() {
  const [enrollments, setEnrollments] = useState([]);
  const [pending, setPending] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [eRes, pRes] = await Promise.all([
        api.get("/admin/pending-enrollments"),
        api.get("/admin/pending-enrollments")
      ]);
      setPending(eRes.data.data || []);
      setEnrollments(eRes.data.data || []);
    } catch { toast.error("Không thể tải dữ liệu"); }
    finally { setLoading(false); }
  };

  useEffect(() => { fetchData(); }, []);

  const handleApprove = async (id) => {
    try { await api.put(`/admin/enrollments/${id}/approve`); toast.success("Đã duyệt"); fetchData(); }
    catch { toast.error("Thất bại"); }
  };

  return (
    <div className="admin-page fade-in">
      <div className="page-header">
        <h1>Quản lý đăng ký học</h1>
        <p>Duyệt yêu cầu đăng ký khóa học của học viên</p>
      </div>
      <div className="table-wrapper">
        {loading ? <div className="page-loading"><div className="spinner" /></div> : (
          <table className="data-table">
            <thead><tr><th>Học viên</th><th>Khóa học</th><th>Lớp</th><th>Ngày đăng ký</th><th>Trạng thái</th><th>Thao tác</th></tr></thead>
            <tbody>
              {enrollments.length === 0
                ? <tr><td colSpan={6} className="empty-state"><p>Không có đăng ký nào</p></td></tr>
                : enrollments.map(e => (
                  <tr key={e.id}>
                    <td>ID: {e.userId}</td>
                    <td>ID: {e.courseId}</td>
                    <td>{e.classId || "—"}</td>
                    <td style={{ fontSize: "0.82rem" }}>{e.enrollDate ? new Date(e.enrollDate).toLocaleDateString("vi-VN") : "—"}</td>
                    <td><span className={`badge ${STATUS_BADGE[e.status]}`}>{STATUS_LABEL[e.status]}</span></td>
                    <td>
                      {e.status === "pending" && (
                        <button className="btn btn-success btn-sm" onClick={() => handleApprove(e.id)}>✅ Duyệt</button>
                      )}
                    </td>
                  </tr>
                ))
              }
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
